import React, { useMemo, useState, useContext, useEffect } from "react";
import {
  View,
  Text,
  StyleSheet,
  Pressable,
  TextInput,
  Image,
  ScrollView,
  Platform,
} from "react-native";
import * as DocumentPicker from "expo-document-picker";
import ConsentModal from "../../components/ConsentModal";
import { AppContext } from "../../../App";
import { useFormNavigation } from "../../utils/navigationUtils";
import Header from "../../components/Header";
import { useTranslation } from "../../i18n";

const COLORS = {
  primary: "#1CA7AE",
  primarySoft: "#E7F6F7",
  background: "#F7F9FA",
  textDark: "#1C1C1E",
  textMuted: "#6B7280",
  border: "#E5E7EB",
};

function CheckRow({ label, checked, onPress }) {
  return (
    <Pressable onPress={onPress} style={styles.checkRow}>
      <View style={[styles.checkBox, checked && styles.checkBoxOn]}>
        {checked && <Text style={styles.checkMark}>✓</Text>}
      </View>
      <Text style={styles.checkLabel}>{label}</Text>
    </Pressable>
  );
}

export default function NotVehicleOwnerForm({ navigation }) {
  const { verification, setVerification, setFormProgress } =
    useContext(AppContext);
  const { updateCurrentStep } = useFormNavigation();
  const { t } = useTranslation();

  const [showConsentModal, setShowConsentModal] = useState(false);

  const [driverFirstName, setDriverFirstName] =
    useState(verification?.driver?.firstName || "");
  const [driverLastName, setDriverLastName] =
    useState(verification?.driver?.lastName || "");
  const [ownerType, setOwnerType] =
    useState(verification?.owner?.type || null);
  const [ownerFirstName, setOwnerFirstName] =
    useState(verification?.owner?.firstName || "");
  const [ownerLastName, setOwnerLastName] =
    useState(verification?.owner?.lastName || "");
  const [ownerOrganizationName, setOwnerOrganizationName] =
    useState(verification?.owner?.organizationName || "");
  const [selectedFileName, setSelectedFileName] =
    useState(verification?.owner?.procurationFileName || "");

  // ✅ NEW: skip document checkbox
  const [skipDocument, setSkipDocument] = useState(
    verification?.owner?.skipProcuration === true
  );

  useEffect(() => {
    updateCurrentStep("not_vehicle_owner_form_screen");
  }, []);

  useEffect(() => {
    const timeout = setTimeout(() => {
      if (!driverFirstName && !driverLastName) return;

      setVerification((prev) => ({
        ...prev,
        driver: {
          firstName: driverFirstName,
          lastName: driverLastName,
        },
        owner:
          ownerType === "PHYSIQUE"
            ? {
                type: "PHYSIQUE",
                firstName: ownerFirstName,
                lastName: ownerLastName,
                procurationFileName: skipDocument ? null : selectedFileName,
                skipProcuration: skipDocument,
              }
            : ownerType === "MORALE"
            ? {
                type: "MORALE",
                organizationName: ownerOrganizationName,
                procurationFileName: skipDocument ? null : selectedFileName,
                skipProcuration: skipDocument,
              }
            : null,
      }));
    }, 800);

    return () => clearTimeout(timeout);
  }, [
    driverFirstName,
    driverLastName,
    ownerType,
    ownerFirstName,
    ownerLastName,
    ownerOrganizationName,
    selectedFileName,
    skipDocument,
  ]);

  const isOwnerPhysique = ownerType === "PHYSIQUE";
  const isOwnerMorale = ownerType === "MORALE";

  const allFieldsFilled = useMemo(() => {
    if (!driverFirstName || !driverLastName || !ownerType) return false;
    if (isOwnerPhysique) return ownerFirstName && ownerLastName;
    if (isOwnerMorale) return ownerOrganizationName;
    return false;
  }, [
    driverFirstName,
    driverLastName,
    ownerType,
    isOwnerPhysique,
    isOwnerMorale,
    ownerFirstName,
    ownerLastName,
    ownerOrganizationName,
  ]);

  const handlePickDocument = async () => {
    if (skipDocument) return;

    if (Platform.OS === "web") {
      const input = document.createElement("input");
      input.type = "file";
      input.accept = ".pdf,image/*";
      input.onchange = (e) => {
        const file = e.target.files?.[0];
        if (file) setSelectedFileName(file.name);
      };
      input.click();
      return;
    }

    const result = await DocumentPicker.getDocumentAsync({
      type: ["application/pdf", "image/*"],
    });

    if (result.assets?.[0]) {
      setSelectedFileName(result.assets[0].name);
    }
  };

  const handleContinue = () => {
    setFormProgress((prev) => ({
      ...prev,
      completedSteps: [
        ...new Set([...prev.completedSteps, "not_vehicle_owner_form_screen"]),
      ],
    }));
    setShowConsentModal(true);
  };

  return (
    <View style={styles.screen}>
      <Header />

      <ScrollView contentContainerStyle={styles.scroll}>
        <Pressable
          style={styles.backButton}
          onPress={() => navigation.navigate("ownership_screen")}
        >
          <Text style={styles.backIcon}>←</Text>
        </Pressable>

        <Text style={styles.title}>{t("nonOwnerForm.title")}</Text>
        <Text style={styles.subtitle}>{t("nonOwnerForm.subtitle")}</Text>

        {/* DRIVER */}
        <View style={styles.card}>
          <Text style={styles.cardTitle}>{t("nonOwnerForm.driver")}</Text>

          <TextInput
            style={styles.input}
            placeholder={t("nonOwnerForm.driverFirstNamePlaceholder")}
            value={driverFirstName}
            onChangeText={setDriverFirstName}
          />
          <TextInput
            style={styles.input}
            placeholder={t("nonOwnerForm.driverLastNamePlaceholder")}
            value={driverLastName}
            onChangeText={setDriverLastName}
          />
        </View>

        {/* OWNER */}
        <View style={styles.card}>
          <Text style={styles.cardTitle}>{t("nonOwnerForm.owner")}</Text>

          <View style={styles.segment}>
            <Pressable
              style={[
                styles.segmentItem,
                ownerType === "PHYSIQUE" && styles.segmentActive,
              ]}
              onPress={() => setOwnerType("PHYSIQUE")}
            >
              <Text
                style={[
                  styles.segmentText,
                  ownerType === "PHYSIQUE" && styles.segmentTextActive,
                ]}
              >
                {t("nonOwnerForm.physicalPerson")}
              </Text>
            </Pressable>

            <Pressable
              style={[
                styles.segmentItem,
                ownerType === "MORALE" && styles.segmentActive,
              ]}
              onPress={() => setOwnerType("MORALE")}
            >
              <Text
                style={[
                  styles.segmentText,
                  ownerType === "MORALE" && styles.segmentTextActive,
                ]}
              >
                {t("nonOwnerForm.company")}
              </Text>
            </Pressable>
          </View>

          {isOwnerPhysique && (
            <>
              <TextInput
                style={styles.input}
                placeholder={t("nonOwnerForm.ownerFirstNamePlaceholder")}
                value={ownerFirstName}
                onChangeText={setOwnerFirstName}
              />
              <TextInput
                style={styles.input}
                placeholder={t("nonOwnerForm.ownerLastNamePlaceholder")}
                value={ownerLastName}
                onChangeText={setOwnerLastName}
              />
            </>
          )}

          {isOwnerMorale && (
            <TextInput
              style={styles.input}
              placeholder={t("nonOwnerForm.companyNamePlaceholder")}
              value={ownerOrganizationName}
              onChangeText={setOwnerOrganizationName}
            />
          )}
        </View>

        {/* UPLOAD */}
        <View style={styles.card}>
          <Text style={styles.cardTitle}>{t("nonOwnerForm.procuration")}</Text>

          <CheckRow
            label={t("documentUpload.skip")}
            checked={skipDocument}
            onPress={() => {
              setSkipDocument((v) => !v);
              if (!skipDocument) setSelectedFileName("");
            }}
          />

          {!skipDocument && (
            <Pressable style={styles.uploadBox} onPress={handlePickDocument}>
              <Image
                source={require("../../../assets/file_upload.png")}
                style={styles.uploadIcon}
              />
              <Text style={styles.uploadText}>
                {selectedFileName || t("nonOwnerForm.addDocument")}
              </Text>
              <Text style={styles.uploadHint}>
                {t("nonOwnerForm.fileFormats")}
              </Text>
            </Pressable>
          )}
        </View>

        <Pressable
          disabled={!allFieldsFilled}
          onPress={handleContinue}
          style={[
            styles.cta,
            { opacity: allFieldsFilled ? 1 : 0.5 },
          ]}
        >
          <Text style={styles.ctaText}>{t("common.continue")}</Text>
        </Pressable>
      </ScrollView>

      {showConsentModal && (
        <ConsentModal
          onDismiss={() => setShowConsentModal(false)}
          navigation={navigation}
        />
      )}
    </View>
  );
}

